local function send_json_response(status, data)
    ngx.status = status
    ngx.header["Content-Type"] = "application/json; charset=utf-8"
    ngx.say(cjson.encode(data))
    return ngx.exit(status)
end

local function connect_redis()
    local red, err = redis:new()
    if not red then
        return nil, "Failed to create redis instance: " .. (err or "unknown")
    end

    red:set_timeout(REDIS_TIMEOUT)

    local ok, err = red:connect(REDIS_HOST, REDIS_PORT)
    if not ok then
        return nil, "Failed to connect to Redis at " .. REDIS_HOST .. ":" .. REDIS_PORT .. " - " .. (err or "unknown")
    end

    if REDIS_PASSWORD and REDIS_PASSWORD ~= "" then
        local res, err = red:auth(REDIS_PASSWORD)
        if not res then
            return nil, "Redis authentication failed: " .. (err or "unknown")
        end
    end

    return red, nil
end

local function keepalive_redis(red)
    if not red then
        return
    end
    local ok, err = red:set_keepalive(REDIS_KEEPALIVE_TIMEOUT, REDIS_KEEPALIVE_POOL_SIZE)
    if not ok then
        ngx.log(ngx.WARN, "Failed to set Redis keepalive: ", err)
    end
end

local function parse_request_body()
    ngx.req.read_body()
    local body = ngx.req.get_body_data()
    if not body then
        return nil, "Empty request body"
    end

    local ok, data = pcall(cjson.decode, body)
    if not ok then
        return nil, "Invalid JSON in request body: " .. tostring(data)
    end

    return data, nil
end

local function validate_command(command)
    if not command or type(command) ~= "string" or command == "" then
        return false, "Command must be a non-empty string"
    end

    local cmd_lower = string.lower(command)

    if BLOCKED_COMMANDS[cmd_lower] then
        return false, "Command '" .. command .. "' is blocked for security reasons"
    end

    if not ALLOWED_COMMANDS[cmd_lower] then
        return false, "Command '" .. command .. "' is not in the allowed commands list"
    end

    return true, nil
end

local function format_redis_result(result)
    if type(result) == "table" then
        -- Check if it's a redis null bulk reply
        local formatted = {}
        for i, v in ipairs(result) do
            if v == ngx.null then
                formatted[i] = cjson.null
            elseif type(v) == "table" then
                formatted[i] = format_redis_result(v)
            else
                formatted[i] = v
            end
        end
        return formatted
    elseif result == ngx.null then
        return cjson.null
    else
        return result
    end
end

local function execute_command(red, command, args)
    local cmd_lower = string.lower(command)
    local func = red[cmd_lower]

    if not func then
        return nil, "Redis command method '" .. cmd_lower .. "' not found in redis library"
    end

    local result, err
    if args and #args > 0 then
        result, err = func(red, unpack(args))
    else
        result, err = func(red)
    end

    if not result then
        return nil, "Redis command failed: " .. (err or "unknown error")
    end

    return format_redis_result(result), nil
end

local function execute_eval(red, script, num_keys, keys, argv)
    if not script or type(script) ~= "string" or script == "" then
        return nil, "Eval requires a non-empty 'script' field"
    end

    num_keys = tonumber(num_keys) or 0
    keys = keys or {}
    argv = argv or {}

    if type(keys) ~= "table" then
        return nil, "'keys' must be an array"
    end

    if type(argv) ~= "table" then
        return nil, "'argv' must be an array"
    end

    -- Build the arguments for eval: script, numkeys, key1, key2, ..., arg1, arg2, ...
    local eval_args = { script, num_keys }
    for _, k in ipairs(keys) do
        table.insert(eval_args, k)
    end
    for _, a in ipairs(argv) do
        table.insert(eval_args, a)
    end

    local result, err = red:eval(unpack(eval_args))
    if not result then
        return nil, "Redis EVAL failed: " .. (err or "unknown error")
    end

    return format_redis_result(result), nil
end

local function execute_pipeline(red, commands)
    if not commands or type(commands) ~= "table" or #commands == 0 then
        return nil, "Pipeline requires a non-empty 'commands' array"
    end

    -- Validate all commands first
    for i, cmd_entry in ipairs(commands) do
        if type(cmd_entry) ~= "table" then
            return nil, "Pipeline command #" .. i .. " must be a table"
        end

        local command = cmd_entry.command or cmd_entry.cmd
        local ok, err = validate_command(command)
        if not ok then
            return nil, "Pipeline command #" .. i .. ": " .. err
        end
    end

    red:init_pipeline()

    for i, cmd_entry in ipairs(commands) do
        local command = string.lower(cmd_entry.command or cmd_entry.cmd)
        local args = cmd_entry.args or {}
        local func = red[command]

        if not func then
            red:cancel_pipeline()
            return nil, "Pipeline command #" .. i .. ": method '" .. command .. "' not found"
        end

        if args and #args > 0 then
            func(red, unpack(args))
        else
            func(red)
        end
    end

    local results, err = red:commit_pipeline()
    if not results then
        return nil, "Pipeline commit failed: " .. (err or "unknown error")
    end

    local formatted = {}
    for i, result in ipairs(results) do
        formatted[i] = {
            command = (commands[i].command or commands[i].cmd),
            result = format_redis_result(result)
        }
    end

    return formatted, nil
end

-- Authentication middleware (simple token-based)
local function authenticate()
    local auth_token = os.getenv("REDIS_API_TOKEN")
    if not auth_token or auth_token == "" then
        -- No auth configured, skip
        return true
    end

    local header_token = ngx.req.get_headers()["X-API-Token"]
    if not header_token then
        -- Also check Authorization: Bearer <token>
        local auth_header = ngx.req.get_headers()["Authorization"]
        if auth_header then
            header_token = string.match(auth_header, "^Bearer%s+(.+)$")
        end
    end

    if header_token ~= auth_token then
        return false
    end

    return true
end

-- Rate limiting using shared dict
local function check_rate_limit()
    local limit_dict = ngx.shared.redis_api_limit
    if not limit_dict then
        return true
    end

    local client_ip = ngx.var.remote_addr
    local key = "rate:" .. client_ip
    local max_requests = 100  -- per window
    local window = 60  -- seconds

    local current, err = limit_dict:incr(key, 1, 0, window)
    if not current then
        ngx.log(ngx.ERR, "Rate limit error: ", err)
        return true  -- fail open
    end

    if current > max_requests then
        return false
    end

    return true
end

-- Main handler
local function handle_request()
    -- Check rate limiting
    if not check_rate_limit() then
        return send_json_response(429, {
            success = false,
            error = "Rate limit exceeded. Please try again later."
        })
    end

    -- Check authentication
    if not authenticate() then
        return send_json_response(401, {
            success = false,
            error = "Unauthorized. Provide a valid X-API-Token header or Authorization: Bearer <token>."
        })
    end

    local method = ngx.req.get_method()

    -- Handle GET requests (simple commands via query params)
    if method == "GET" then
        local args = ngx.req.get_uri_args()
        local command = args.cmd or args.command

        if not command then
            return send_json_response(400, {
                success = false,
                error = "Missing 'cmd' or 'command' query parameter",
                usage = {
                    single_command = "GET /redis?cmd=GET&args=mykey",
                    with_multiple_args = "GET /redis?cmd=SET&args=mykey&args=myvalue",
                    info = "GET /redis/info",
                    allowed_commands = "GET /redis/commands"
                }
            })
        end

        local ok, err = validate_command(command)
        if not ok then
            return send_json_response(403, {
                success = false,
                error = err
            })
        end

        -- Parse args - can be single value or table
        local cmd_args = args.args
        if cmd_args and type(cmd_args) == "string" then
            cmd_args = { cmd_args }
        end
        cmd_args = cmd_args or {}

        local red, err = connect_redis()
        if not red then
            return send_json_response(503, {
                success = false,
                error = err
            })
        end

        local result, err = execute_command(red, command, cmd_args)
        keepalive_redis(red)

        if not result and err then
            return send_json_response(500, {
                success = false,
                error = err
            })
        end

        return send_json_response(200, {
            success = true,
            command = string.upper(command),
            args = cmd_args,
            result = result
        })
    end

    -- Handle POST requests (complex commands, eval, pipelines)
    if method == "POST" then
        local data, err = parse_request_body()
        if not data then
            return send_json_response(400, {
                success = false,
                error = err,
                usage = {
                    single_command = {
                        command = "GET",
                        args = { "mykey" }
                    },
                    eval_script = {
                        mode = "eval",
                        script = "return redis.call('get', KEYS[1])",
                        num_keys = 1,
                        keys = { "mykey" },
                        argv = {}
                    },
                    pipeline = {
                        mode = "pipeline",
                        commands = {
                            { command = "SET", args = { "key1", "value1" } },
                            { command = "SET", args = { "key2", "value2" } },
                            { command = "MGET", args = { "key1", "key2" } }
                        }
                    }
                }
            })
        end

        local red, err = connect_redis()
        if not red then
            return send_json_response(503, {
                success = false,
                error = err
            })
        end

        -- Select database if specified
        if data.db then
            local db_num = tonumber(data.db)
            if db_num then
                local ok, err = red:select(db_num)
                if not ok then
                    keepalive_redis(red)
                    return send_json_response(400, {
                        success = false,
                        error = "Failed to select database " .. db_num .. ": " .. (err or "unknown")
                    })
                end
            end
        end

        local mode = data.mode or "command"

        -- EVAL mode
        if mode == "eval" then
            local result, err = execute_eval(
                red,
                data.script,
                data.num_keys,
                data.keys,
                data.argv
            )
            keepalive_redis(red)

            if not result and err then
                return send_json_response(500, {
                    success = false,
                    error = err
                })
            end

            return send_json_response(200, {
                success = true,
                mode = "eval",
                result = result
            })
        end

        -- PIPELINE mode
        if mode == "pipeline" then
            local result, err = execute_pipeline(red, data.commands)
            keepalive_redis(red)

            if not result and err then
                return send_json_response(500, {
                    success = false,
                    error = err
                })
            end

            return send_json_response(200, {
                success = true,
                mode = "pipeline",
                count = #result,
                results = result
            })
        end

        -- Single COMMAND mode (default)
        if mode == "command" then
            local command = data.command or data.cmd
            if not command then
                keepalive_redis(red)
                return send_json_response(400, {
                    success = false,
                    error = "Missing 'command' or 'cmd' field in request body"
                })
            end

            local ok, err = validate_command(command)
            if not ok then
                keepalive_redis(red)
                return send_json_response(403, {
                    success = false,
                    error = err
                })
            end

            local cmd_args = data.args or {}
            if type(cmd_args) ~= "table" then
                cmd_args = { cmd_args }
            end

            local result, err = execute_command(red, command, cmd_args)
            keepalive_redis(red)

            if not result and err then
                return send_json_response(500, {
                    success = false,
                    error = err
                })
            end

            return send_json_response(200, {
                success = true,
                command = string.upper(command),
                args = cmd_args,
                result = result
            })
        end

        -- MULTI-COMMAND mode (execute multiple commands sequentially, not pipelined)
        if mode == "multi" then
            local commands = data.commands
            if not commands or type(commands) ~= "table" or #commands == 0 then
                keepalive_redis(red)
                return send_json_response(400, {
                    success = false,
                    error = "Multi mode requires a non-empty 'commands' array"
                })
            end

            local results = {}
            for i, cmd_entry in ipairs(commands) do
                local command = cmd_entry.command or cmd_entry.cmd
                local ok, err = validate_command(command)
                if not ok then
                    keepalive_redis(red)
                    return send_json_response(403, {
                        success = false,
                        error = "Command #" .. i .. ": " .. err
                    })
                end

                local cmd_args = cmd_entry.args or {}
                local result, err = execute_command(red, command, cmd_args)
                if not result and err then
                    results[i] = {
                        command = string.upper(command),
                        args = cmd_args,
                        success = false,
                        error = err
                    }
                else
                    results[i] = {
                        command = string.upper(command),
                        args = cmd_args,
                        success = true,
                        result = result
                    }
                end
            end

            keepalive_redis(red)

            return send_json_response(200, {
                success = true,
                mode = "multi",
                count = #results,
                results = results
            })
        end

        keepalive_redis(red)
        return send_json_response(400, {
            success = false,
            error = "Unknown mode: " .. tostring(mode),
            available_modes = { "command", "eval", "pipeline", "multi" }
        })
    end

    -- Handle special routes
    local uri = ngx.var.uri

    -- GET /redis/commands - list allowed commands
    if uri == "/redis/commands" or uri == "/redis/commands/" then
        local cmds = {}
        for cmd, _ in pairs(ALLOWED_COMMANDS) do
            table.insert(cmds, string.upper(cmd))
        end
        table.sort(cmds)

        return send_json_response(200, {
            success = true,
            allowed_commands = cmds,
            total = #cmds
        })
    end

    -- GET /redis/info - Redis server info
    if uri == "/redis/info" or uri == "/redis/info/" then
        local red, err = connect_redis()
        if not red then
            return send_json_response(503, {
                success = false,
                error = err
            })
        end

        local section = ngx.req.get_uri_args().section
        local result, err
        if section then
            result, err = red:info(section)
        else
            result, err = red:info()
        end
        keepalive_redis(red)

        if not result then
            return send_json_response(500, {
                success = false,
                error = "Failed to get Redis info: " .. (err or "unknown")
            })
        end

        -- Parse info string into structured data
        local info_data = {}
        local current_section = "default"
        for line in tostring(result):gmatch("[^\r\n]+") do
            local section_name = line:match("^#%s*(.+)$")
            if section_name then
                current_section = section_name
                info_data[current_section] = {}
            else
                local key, value = line:match("^([^:]+):(.+)$")
                if key and value then
                    if not info_data[current_section] then
                        info_data[current_section] = {}
                    end
                    info_data[current_section][key] = value
                end
            end
        end

        return send_json_response(200, {
            success = true,
            info = info_data
        })
    end

    -- GET /redis/health - Health check
    if uri == "/redis/health" or uri == "/redis/health/" then
        local red, err = connect_redis()
        if not red then
            return send_json_response(503, {
                success = false,
                status = "unhealthy",
                error = err
            })
        end

        local result, err = red:ping()
        keepalive_redis(red)

        if not result or result ~= "PONG" then
            return send_json_response(503, {
                success = false,
                status = "unhealthy",
                error = err or "Unexpected PING response"
            })
        end

        return send_json_response(200, {
            success = true,
            status = "healthy",
            redis_host = REDIS_HOST,
            redis_port = REDIS_PORT,
            timestamp = ngx.now()
        })
    end

    -- Method not allowed
    return send_json_response(405, {
        success = false,
        error = "Method " .. method .. " not allowed. Use GET or POST.",
        endpoints = {
            ["GET /redis?cmd=<command>&args=<arg1>&args=<arg2>"] = "Execute simple Redis command",
            ["POST /redis"] = "Execute commands (modes: command, eval, pipeline, multi)",
            ["GET /redis/commands"] = "List allowed commands",
            ["GET /redis/info"] = "Get Redis server info",
            ["GET /redis/health"] = "Health check endpoint"
        }
    })
end

-- Execute main handler with error protection
local ok, err = pcall(handle_request)
if not ok then
    ngx.log(ngx.ERR, "Redis API error: ", err)
    send_json_response(500, {
        success = false,
        error = "Internal server error"
    })
end